#include <limits.h>
#include <stdio.h>

int main(void) {
    long long value;
    if (scanf("%lld", &value) != 1) return 1;
    if (value < SCHAR_MIN || value > SCHAR_MAX) puts("out-of-range");
    else printf("%d\n", (int)(signed char)value);
    return 0;
}
